#include <iostream>

using namespace std;

int *createValue()
{
    int *ptr = new int(42); // allocated on the HEAP
    return ptr;             // the heap memory survives, even though ptr itself goes away
}

int main()
{
    int *result = createValue();

    cout << *result << endl;

    delete result;

    return 0;
}

int *createValueBroken()
{
    int localValue = 42;   // lives on the STACK, inside this function's frame
    return &localValue;    // DANGER — returning the address of a variable about to be destroyed!
}

